// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.packed;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertNotEquals;
import static org.junit.jupiter.api.Assertions.assertThrows;

import org.junit.jupiter.api.Test;

class PackedExpressionInternerTest {

	@Test
	void repeatedInsertionReturnsExistingExpression() {
		PackedExpressionInterner interner = new PackedExpressionInterner(2, 4);
		int[] children = { 11, 12, 13 };

		int first = interner.internLogical(1, 7, 3, 5, 9, children, 0, children.length);
		int repeated = interner.internLogical(1, 7, 3, 5, 9, children, 0, children.length);

		assertEquals(first, repeated);
		assertEquals(1, interner.size());
		assertEquals(1, interner.groupId(first));
		assertEquals(3, interner.childCount(first));
		assertEquals(13, interner.childGroupId(first, 2));
	}

	@Test
	void explicitHashCollisionStillUsesStructuralEquality() {
		PackedExpressionInterner interner = new PackedExpressionInterner(2, 2);
		long collision = 42L;

		int left = interner.internLogicalHashed(collision, 1, 7, 3, 5, 9, new int[] { 11 }, 0, 1);
		int right = interner.internLogicalHashed(collision, 2, 8, 3, 5, 9, new int[] { 11 }, 0, 1);

		assertNotEquals(left, right);
		assertEquals(2, interner.size());
	}

	@Test
	void structuralDuplicateCannotMoveToAnotherGroup() {
		PackedExpressionInterner interner = new PackedExpressionInterner(2, 2);
		int[] children = { 11, 12 };
		interner.internLogical(1, 7, 3, 5, 9, children, 0, children.length);

		assertThrows(PackedMemoInvariantException.class,
				() -> interner.internLogical(2, 7, 3, 5, 9, children, 0, children.length));
	}

	@Test
	void resizePreservesEveryInternedRow() {
		PackedExpressionInterner interner = new PackedExpressionInterner(1, 1);
		for (int i = 1; i <= 100; i++) {
			assertEquals(i, interner.internLogical(i, i, i + 1, i + 2, i + 3, new int[] { i + 4 }, 0, 1));
		}

		assertEquals(100, interner.size());
		for (int i = 1; i <= 100; i++) {
			assertEquals(i, interner.internLogical(i, i, i + 1, i + 2, i + 3, new int[] { i + 4 }, 0, 1));
		}
		assertEquals(100, interner.size());
	}
}
